import{_ as e,c as t,o as a,a5 as r}from"./chunks/framework.DwbewbAn.js";const k=JSON.parse('{"title":"网络","description":"","frontmatter":{},"headers":[],"relativePath":"doc/DevOps/Kubernetes/基础/Network/networking.md","filePath":"packages/doc/src/DevOps/Kubernetes/基础/Network/networking.md","lastUpdated":1705214817000}'),o={name:"doc/DevOps/Kubernetes/基础/Network/networking.md"},i=r('<h1 id="网络" tabindex="-1">网络 <a class="header-anchor" href="#网络" aria-label="Permalink to &quot;网络&quot;">​</a></h1><p>Kubernetes 中的网络可以说对初次接触 Kubernetes 或者没有网络方面经验的人来说可能是其中最难的部分。Kubernetes 本身并不提供网络功能，只是把网络接口开放出来，通过插件的形式实现。</p><h2 id="网络要解决的问题" tabindex="-1">网络要解决的问题 <a class="header-anchor" href="#网络要解决的问题" aria-label="Permalink to &quot;网络要解决的问题&quot;">​</a></h2><p>既然 Kubernetes 中将容器的联网通过插件的方式来实现，那么该如何解决容器的联网问题呢？</p><p>如果您在本地单台机器上运行 docker 容器的话会注意到所有容器都会处在 <code>docker0</code> 网桥自动分配的一个网络 IP 段内（172.17.0.1/16）。该值可以通过 docker 启动参数 <code>--bip</code> 来设置。这样所有本地的所有的容器都拥有了一个 IP 地址，而且还是在一个网段内彼此就可以互相通信了。</p><p>但是 Kubernetes 管理的是集群，Kubernetes 中的网络要解决的核心问题就是每台主机的 IP 地址网段划分，以及单个容器的 IP 地址分配。概括为：</p><ul><li>保证每个 Pod 拥有一个集群内唯一的 IP 地址</li><li>保证不同节点的 IP 地址划分不会重复</li><li>保证跨节点的 Pod 可以互相通信</li><li>保证不同节点的 Pod 可以与跨节点的主机互相通信</li></ul><p>为了解决该问题，出现了一系列开源的 Kubernetes 中的网络插件与方案，如：</p><ul><li>flannel</li><li>calico</li><li>contiv</li><li>weave</li><li>kube-router</li><li>cilium</li><li>canal</li></ul><p>还有很多就不一一列举了（请见 <a href="https://jimmysong.io/awesome-cloud-native/#network" target="_blank" rel="noreferrer">云原生开源项目大全</a>），只要实现 Kubernetes 官方的设计的 <a href="./cni">CNI - Container Network Interface（容器网络接口）</a> 就可以自己写一个网络插件。</p><p>本章将以当前最常用的 flannel、calico 和 cilium 等插件为例解析。</p>',11),n=[i];function l(c,s,d,p,u,_){return a(),t("div",null,n)}const b=e(o,[["render",l]]);export{k as __pageData,b as default};
